var doc = uiapp.ActiveUIDocument.Document;
var tempDir = System.IO.Path.Combine(System.IO.Path.GetTempPath(), "aware-revit-ifc");
System.IO.Directory.CreateDirectory(tempDir);
var opts = new IFCExportOptions();
opts.FileVersion = IFCVersion.IFC4;
var name = (doc.Title ?? "export") + ".ifc";
bool ok;
using (var tx = new Transaction(doc, "AWARE IFC export"))
{
    tx.Start();
    ok = doc.Export(tempDir, name, opts);
    tx.Commit();
}
return new { exported = ok, path = System.IO.Path.Combine(tempDir, name) };
